    pub walk_length: u32,       // default: ceil(log2(n))
    pub trust_seed: Vec<u256>,  // Protocol-tier agents
    pub threshold: f64,         // flag threshold (default 0.05)
}

/// Result of Sybil detection scan.
pub struct SybilScanResult {
    pub flagged_agents: Vec<u256>,          // passport IDs below threshold
    pub clusters: Vec<SybilCluster>,        // detected Sybil clusters
    pub honest_region_size: usize,
    pub scan_timestamp: u64,
}

pub struct SybilCluster {
    pub members: Vec<u256>,                 // passport IDs in cluster
    pub internal_edge_density: f64,         // edges within cluster / possible edges
    pub external_edge_count: u32,           // edges to honest region (attack edges)
    pub estimated_sybil_probability: f64,   // P(cluster is Sybil)
}
```

